const inp = $input.first().json;

// Helpers
function b64(str) { return Buffer.from(str, 'utf-8').toString('base64'); }
function pad(n)   { return String(n).padStart(2,'0'); }

const src  = inp.course_id        || 'unknown_src';
const tgt  = inp.target_course_id || 'unknown_tgt';
const sl   = inp.source_language  || 'fr';
const tl   = (inp.target_language || 'en-US').split('-')[0];
const dir  = `${sl}>${tl}`;
const now  = new Date();
const date = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const base = `07_runs/${src}/output`;

// 1. Final HTML
const htmlContent   = inp.final_html        || '';
const htmlPath      = `${base}/${tgt}_localized_${dir}.html`;
const htmlB64       = b64(htmlContent);

// 2. Decision log (A4 + A5 + A6 merged)
const logObj = {
  meta: { course_id: src, target_course_id: tgt, direction: dir, date, score_total: inp.score_total || null },
  a4_swap_log:   inp.a4_swap_log   || [],
  a5_qa_report:  inp.a5_qa_report  || {},
  a6_issue_log:  inp.a6_issue_log  || [],
  structural_checks: inp.structural_checks || []
};
const logPath = `${base}/${tgt}_decision_log_${dir}.json`;
const logB64  = b64(JSON.stringify(logObj, null, 2));

// 3. TM patch CSV (new domain TM entries)
const tmEntries = inp.domain_tm_patch || [];
let csvRows = 'source_term,target_term,direction,domain,category,context_note,do_not_translate,validated,first_seen_course,last_updated\n';
for (const e of tmEntries) {
  csvRows += [
    e.source_term||'', e.target_term||'', dir,
    e.domain||inp.detected_domain||'', e.category||'',
    (e.context_note||'').replace(/,/g,'；'),
    e.do_not_translate||false, 'false', src, date
  ].join(',') + '\n';
}
const tmPath = `${base}/${tgt}_tm_patch_${dir}.csv`;
const tmB64  = b64(csvRows);

// 4. Google Doc title + body text
const docTitle = `[CLS Review] ${tgt} — ${sl.toUpperCase()}→${tl.toUpperCase()} — ${date}`;
const docBody  = `Course Localization Review\n\nSource ID : ${src}\nTarget ID : ${tgt}\nDirection : ${dir}\nDate      : ${date}\n\nQA Score  : ${inp.score_total || 'N/A'}/100\nStructure : ${inp.structural_integrity ? '✅ OK' : '❌ BLOCKED'}\n\nGitHub outputs:\n- ${htmlPath}\n- ${logPath}\n- ${tmPath}\n\n--- A5 QA Summary ---\n${inp.a5_summary || 'No QA summary available.'}\n\n--- A6 Issues ---\n${(inp.a6_issue_log||[]).map(i=>`[${i.severity}] ${i.location}: ${i.issue}`).join('\n') || 'None.'}`;

return [{ json: {
  htmlPath, htmlB64,
  logPath,  logB64,
  tmPath,   tmB64,
  docTitle, docBody,
  repo: 'jeremieborrotzu-blip/Ressources_Loc_OSS',
  course_id: src, target_course_id: tgt,
  direction: dir, date,
  score_total:           inp.score_total,
  structural_integrity:  inp.structural_integrity,
  enabled_modules:       inp.enabled_modules || []
}}];

const prep   = $('Prepare Files').first().json;
const ghHtml = $('Push HTML').first().json;
const ghLog  = $('Push Decision Log').first().json;
const ghTm   = $('Push TM Patch').first().json;
const gdoc   = $('Create Google Doc').first().json;

const ghBase = `https://github.com/${prep.repo}/blob/main/`;

return [{ json: {
  status: 'DELIVERED',
  course_id:           prep.course_id,
  target_course_id:    prep.target_course_id,
  direction:           prep.direction,
  date:                prep.date,
  score_total:         prep.score_total,
  structural_integrity: prep.structural_integrity,
  deliverables: {
    html_github:   ghBase + prep.htmlPath,
    log_github:    ghBase + prep.logPath,
    tm_patch:      ghBase + prep.tmPath,
    google_doc_id: gdoc.documentId || null,
    google_doc_url: gdoc.documentId ? `https://docs.google.com/document/d/${gdoc.documentId}/edit` : null
  },
  next_steps: [
    'Review Google Doc for human QA',
    'Merge TM patch CSV into domain translation memory after validation',
    'Re-inject HTML under target course ID on OC platform'
  ]
}}];

